"use client";

import React, { useState, useEffect, useCallback } from "react";
import {
  getDemoAudit,
  runAudit,
  getMetrics,
  type AuditData,
  type MetricsData,
  type Vulnerability,
} from "../lib/api";

// ─── Severity config ──────────────────────────────────────────────────────────
const SEVERITY_CONFIG = {
  CRITICAL: {
    label: "Critical",
    color: "#ef4444",
    bg: "rgba(239,68,68,0.12)",
    dot: "#ef4444",
  },
  HIGH: {
    label: "High",
    color: "#f97316",
    bg: "rgba(249,115,22,0.12)",
    dot: "#f97316",
  },
  MEDIUM: {
    label: "Medium",
    color: "#eab308",
    bg: "rgba(234,179,8,0.12)",
    dot: "#eab308",
  },
  LOW: {
    label: "Low",
    color: "#6b7280",
    bg: "rgba(107,114,128,0.12)",
    dot: "#6b7280",
  },
};

// ─── Score Ring Component ─────────────────────────────────────────────────────
function ScoreRing({
  score,
  label,
  color,
}: {
  score: number;
  label: string;
  color: string;
}) {
  const radius = 54;
  const circumference = 2 * Math.PI * radius;
  const filled = (score / 100) * circumference;

  return (
    <div className="flex flex-col items-center gap-3">
      <div className="relative w-32 h-32">
        <svg viewBox="0 0 128 128" className="w-full h-full -rotate-90">
          <circle
            cx="64"
            cy="64"
            r={radius}
            fill="none"
            stroke="rgba(255,255,255,0.06)"
            strokeWidth="10"
          />
          <circle
            cx="64"
            cy="64"
            r={radius}
            fill="none"
            stroke={color}
            strokeWidth="10"
            strokeDasharray={`${filled} ${circumference}`}
            strokeLinecap="round"
            style={{
              transition: "stroke-dasharray 1.2s cubic-bezier(0.4,0,0.2,1)",
            }}
          />
        </svg>
        <div className="absolute inset-0 flex items-center justify-center">
          <span className="text-2xl font-bold" style={{ color }}>
            {score}
            <span className="text-sm font-normal text-gray-400">%</span>
          </span>
        </div>
      </div>
      <span className="text-xs font-semibold tracking-widest uppercase text-gray-400">
        {label}
      </span>
    </div>
  );
}

// ─── Metric Card ──────────────────────────────────────────────────────────────
function MetricCard({
  label,
  value,
  icon,
  accent,
}: {
  label: string;
  value: string;
  icon: string;
  accent: string;
}) {
  return (
    <div
      className="metric-card group"
      style={{ "--accent": accent } as React.CSSProperties}
    >
      <div className="metric-glow" />
      <span className="metric-icon material-symbols-outlined">{icon}</span>
      <div>
        <p className="metric-value">{value}</p>
        <p className="metric-label">{label}</p>
      </div>
    </div>
  );
}

// ─── Severity Badge ───────────────────────────────────────────────────────────
function SeverityBadge({ severity }: { severity: string }) {
  const cfg =
    SEVERITY_CONFIG[severity as keyof typeof SEVERITY_CONFIG] ??
    SEVERITY_CONFIG.LOW;
  return (
    <span
      className="px-2.5 py-0.5 rounded-full text-xs font-bold tracking-wider uppercase"
      style={{
        color: cfg.color,
        background: cfg.bg,
        border: `1px solid ${cfg.color}33`,
      }}
    >
      {cfg.label}
    </span>
  );
}

// ─── Vulnerability Row ────────────────────────────────────────────────────────
function VulnRow({ vuln, index }: { vuln: Vulnerability; index: number }) {
  const [expanded, setExpanded] = useState(false);
  const cfg = SEVERITY_CONFIG[vuln.severity] ?? SEVERITY_CONFIG.LOW;

  return (
    <>
      <tr
        className="vuln-row cursor-pointer"
        onClick={() => setExpanded(!expanded)}
        style={{ animationDelay: `${index * 60}ms` }}
      >
        <td className="px-6 py-4">
          <div className="flex items-center gap-2">
            <span
              className="w-2 h-2 rounded-full flex-shrink-0"
              style={{ background: cfg.dot, boxShadow: `0 0 6px ${cfg.dot}` }}
            />
            <code className="text-sm text-blue-300 font-mono">{vuln.file}</code>
            <span className="text-xs text-gray-500">:{vuln.line}</span>
          </div>
        </td>
        <td className="px-6 py-4 text-sm text-gray-300">
          {vuln.type.replace(/_/g, " ")}
        </td>
        <td className="px-6 py-4">
          <SeverityBadge severity={vuln.severity} />
        </td>
        <td className="px-6 py-4">
          <div className="flex items-center gap-1.5">
            <div className="h-1.5 flex-1 rounded-full bg-white/5">
              <div
                className="h-full rounded-full"
                style={{
                  width: `${vuln.confidence * 100}%`,
                  background: "linear-gradient(90deg, #6366f1, #8b5cf6)",
                }}
              />
            </div>
            <span className="text-xs text-gray-500">
              {Math.round(vuln.confidence * 100)}%
            </span>
          </div>
        </td>
        <td className="px-6 py-4">
          <span className="flex items-center gap-1.5 text-emerald-400 text-xs font-semibold">
            <span className="material-symbols-outlined text-sm">
              check_circle
            </span>{" "}
            Generated
          </span>
        </td>
        <td className="px-6 py-4 text-right">
          <span
            className="material-symbols-outlined text-gray-500 text-sm transition-transform duration-200"
            style={{
              transform: expanded ? "rotate(180deg)" : "rotate(0deg)",
              display: "inline-block",
            }}
          >
            expand_more
          </span>
        </td>
      </tr>
      {expanded && (
        <tr className="bg-white/[0.02] border-b border-white/5">
          <td colSpan={6} className="px-6 py-4">
            <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
              <div>
                <p className="text-xs text-gray-500 font-semibold uppercase tracking-wider mb-2">
                  Vulnerable Code
                </p>
                <code className="block text-xs bg-black/40 text-red-300 p-3 rounded-lg font-mono border border-red-500/10 whitespace-pre-wrap break-all">
                  {vuln.code}
                </code>
              </div>
              <div className="space-y-3">
                <div>
                  <p className="text-xs text-gray-500 font-semibold uppercase tracking-wider mb-1">
                    Description
                  </p>
                  <p className="text-sm text-gray-300">{vuln.description}</p>
                </div>
                <div>
                  <p className="text-xs text-gray-500 font-semibold uppercase tracking-wider mb-1">
                    Fix Suggestion
                  </p>
                  <p className="text-sm text-emerald-300">
                    {vuln.fix_suggestion}
                  </p>
                </div>
              </div>
            </div>
          </td>
        </tr>
      )}
    </>
  );
}

// ─── PR Card ──────────────────────────────────────────────────────────────────
function PRCard({ vuln, index }: { vuln: Vulnerability; index: number }) {
  const cfg = SEVERITY_CONFIG[vuln.severity] ?? SEVERITY_CONFIG.LOW;
  return (
    <div className="pr-card" style={{ animationDelay: `${index * 80}ms` }}>
      <div className="flex items-start justify-between mb-3">
        <div className="flex items-center gap-3">
          <div
            className="w-9 h-9 rounded-lg flex items-center justify-center"
            style={{
              background: "rgba(99,102,241,0.15)",
              border: "1px solid rgba(99,102,241,0.2)",
            }}
          >
            <span className="material-symbols-outlined text-indigo-400 text-lg">
              alt_route
            </span>
          </div>
          <div>
            <p className="text-sm font-semibold text-white leading-tight">
              Fix {vuln.type.replace(/_/g, " ")}
            </p>
            <code className="text-xs text-gray-500 font-mono">
              {vuln.file}:{vuln.line}
            </code>
          </div>
        </div>
        <span
          className="text-xs px-2 py-0.5 rounded-full font-medium"
          style={{ color: cfg.color, background: cfg.bg }}
        >
          Pending
        </span>
      </div>
      <p className="text-xs text-gray-400 mb-4 leading-relaxed">
        {vuln.fix_suggestion}
      </p>
      <button className="w-full py-2 rounded-lg text-xs font-semibold text-indigo-400 border border-indigo-500/20 hover:bg-indigo-500/10 transition-colors">
        View PR →
      </button>
    </div>
  );
}

// ─── Summary Bar ──────────────────────────────────────────────────────────────
function SummaryBar({ summary }: { summary: AuditData["summary"] }) {
  const total = summary.total || 1;
  const bars = [
    {
      key: "critical",
      label: "Critical",
      color: "#ef4444",
      count: summary.critical,
    },
    { key: "high", label: "High", color: "#f97316", count: summary.high },
    { key: "medium", label: "Medium", color: "#eab308", count: summary.medium },
    { key: "low", label: "Low", color: "#6b7280", count: summary.low },
  ];
  return (
    <div className="space-y-3">
      {bars.map((b) => (
        <div key={b.key} className="flex items-center gap-3">
          <span className="w-14 text-xs text-gray-400">{b.label}</span>
          <div className="flex-1 h-2 rounded-full bg-white/5 overflow-hidden">
            <div
              className="h-full rounded-full transition-all duration-1000"
              style={{
                width: `${(b.count / total) * 100}%`,
                background: b.color,
                boxShadow: `0 0 8px ${b.color}55`,
              }}
            />
          </div>
          <span
            className="w-6 text-right text-xs font-bold"
            style={{ color: b.color }}
          >
            {b.count}
          </span>
        </div>
      ))}
    </div>
  );
}

// ─── Main Dashboard ───────────────────────────────────────────────────────────
export default function DashboardUI() {
  const [loading, setLoading] = useState(false);
  const [auditData, setAuditData] = useState<AuditData | null>(null);
  const [metrics, setMetrics] = useState<MetricsData | null>(null);
  const [error, setError] = useState<string | null>(null);
  const [severityFilter, setSeverityFilter] = useState("ALL");
  const [scanMode, setScanMode] = useState<"demo" | "live">("demo");
  const [lastAudit, setLastAudit] = useState<string | null>(null);
  const [apiStatus, setApiStatus] = useState<"online" | "offline" | "checking">(
    "checking",
  );

  // Check API health on mount
  useEffect(() => {
    const check = async () => {
      try {
        const res = await fetch(
          `${process.env.NEXT_PUBLIC_API_URL || "http://localhost:3000"}/health`,
        );
        setApiStatus(res.ok ? "online" : "offline");
      } catch {
        setApiStatus("offline");
      }
    };
    check();
  }, []);

  const handleRunAudit = useCallback(async () => {
    setLoading(true);
    setError(null);
    try {
      let result;
      if (scanMode === "demo" || apiStatus === "offline") {
        result = await getDemoAudit();
      } else {
        result = await runAudit([
          {
            file: "routes/user.js",
            content: `const express = require('express');\nconst db = require('./db');\nrouter.get('/user/:id', (req, res) => {\n  const userId = req.params.id;\n  db.query(\`SELECT * FROM users WHERE id = '\${userId}'\`, (err, rows) => {\n    res.json(rows);\n  });\n});`,
          },
        ]);
      }
      if (result.success) {
        setAuditData(result.data);
        setLastAudit(new Date().toLocaleTimeString());
        // Fetch metrics separately
        try {
          const m = await getMetrics();
          if (m.success) setMetrics(m.data);
        } catch {}
      } else {
        setError("Audit failed. Please try again.");
      }
    } catch {
      setError(
        "Cannot reach the API server. Run in demo mode or check your connection.",
      );
    } finally {
      setLoading(false);
    }
  }, [scanMode, apiStatus]);

  const filteredVulns =
    auditData?.vulnerabilities.filter(
      (v) => severityFilter === "ALL" || v.severity === severityFilter,
    ) ?? [];

  const beforeScore = 100 - (auditData?.summary.total ?? 0) * 8;
  const afterScore = auditData?.overallScore ?? 0;

  return (
    <>
      <style>{`
        @import url('https://fonts.googleapis.com/css2?family=Syne:wght@400;500;600;700;800&family=JetBrains+Mono:wght@400;500&display=swap');
        @import url('https://fonts.googleapis.com/css2?family=Material+Symbols+Outlined:opsz,wght,FILL,GRAD@20..48,100..700,0..1,-50..200');

        * { box-sizing: border-box; }

        body {
          background: #050508;
          font-family: 'Syne', sans-serif;
        }

        .dashboard-root {
          min-height: 100vh;
          background: #050508;
          color: #e2e8f0;
          font-family: 'Syne', sans-serif;
        }

        /* Grid noise overlay */
        .dashboard-root::before {
          content: '';
          position: fixed;
          inset: 0;
          background-image:
            linear-gradient(rgba(99,102,241,0.03) 1px, transparent 1px),
            linear-gradient(90deg, rgba(99,102,241,0.03) 1px, transparent 1px);
          background-size: 40px 40px;
          pointer-events: none;
          z-index: 0;
        }

        .content { position: relative; z-index: 1; }

        /* Nav */
        .top-nav {
          position: sticky;
          top: 0;
          z-index: 50;
          background: rgba(5,5,8,0.85);
          backdrop-filter: blur(20px);
          border-bottom: 1px solid rgba(255,255,255,0.06);
          padding: 0 2rem;
          height: 64px;
          display: flex;
          align-items: center;
          justify-content: space-between;
        }

        .logo {
          font-size: 1.125rem;
          font-weight: 800;
          letter-spacing: -0.03em;
          background: linear-gradient(135deg, #fff 0%, #a5b4fc 100%);
          -webkit-background-clip: text;
          -webkit-text-fill-color: transparent;
        }

        .nav-links { display: flex; gap: 2rem; }
        .nav-link {
          font-size: 0.8125rem;
          font-weight: 600;
          color: #6b7280;
          letter-spacing: 0.02em;
          text-decoration: none;
          transition: color 0.2s;
          cursor: pointer;
        }
        .nav-link:hover, .nav-link.active { color: #fff; }
        .nav-link.active { color: #a5b4fc; }

        .api-dot {
          width: 7px; height: 7px;
          border-radius: 50%;
          display: inline-block;
        }
        .api-dot.online { background: #10b981; box-shadow: 0 0 6px #10b981; }
        .api-dot.offline { background: #ef4444; box-shadow: 0 0 6px #ef4444; }
        .api-dot.checking { background: #eab308; animation: blink 1s infinite; }
        @keyframes blink { 0%,100%{opacity:1} 50%{opacity:0.3} }

        /* Hero */
        .hero {
          text-align: center;
          padding: 5rem 2rem 4rem;
          position: relative;
        }
        .hero-glow {
          position: absolute;
          top: 0; left: 50%;
          transform: translateX(-50%);
          width: 600px; height: 300px;
          background: radial-gradient(ellipse at center top, rgba(99,102,241,0.12) 0%, transparent 70%);
          pointer-events: none;
        }
        .hero h1 {
          font-size: clamp(2rem, 5vw, 3.5rem);
          font-weight: 800;
          letter-spacing: -0.04em;
          color: #fff;
          margin-bottom: 1rem;
          line-height: 1.1;
        }
        .hero p {
          color: #6b7280;
          font-size: 1rem;
          max-width: 480px;
          margin: 0 auto 2.5rem;
          line-height: 1.7;
        }

        .mode-toggle {
          display: inline-flex;
          background: rgba(255,255,255,0.04);
          border: 1px solid rgba(255,255,255,0.08);
          border-radius: 9999px;
          padding: 4px;
          margin-bottom: 1.5rem;
        }
        .mode-btn {
          padding: 6px 18px;
          border-radius: 9999px;
          font-size: 0.75rem;
          font-weight: 700;
          letter-spacing: 0.05em;
          cursor: pointer;
          border: none;
          transition: all 0.2s;
          font-family: 'Syne', sans-serif;
        }
        .mode-btn.active {
          background: #6366f1;
          color: #fff;
        }
        .mode-btn.inactive {
          background: transparent;
          color: #6b7280;
        }

        .run-btn {
          position: relative;
          padding: 1rem 3rem;
          border-radius: 9999px;
          font-size: 1rem;
          font-weight: 700;
          letter-spacing: 0.02em;
          cursor: pointer;
          border: none;
          font-family: 'Syne', sans-serif;
          background: linear-gradient(135deg, #6366f1, #8b5cf6);
          color: #fff;
          transition: all 0.3s;
          box-shadow: 0 0 0 0 rgba(99,102,241,0.4);
        }
        .run-btn:not(:disabled):hover {
          transform: translateY(-2px);
          box-shadow: 0 8px 32px rgba(99,102,241,0.4), 0 0 0 0 rgba(99,102,241,0);
        }
        .run-btn:disabled {
          opacity: 0.7;
          cursor: not-allowed;
        }
        .run-btn.pulse {
          animation: btn-pulse 2s infinite;
        }
        @keyframes btn-pulse {
          0% { box-shadow: 0 0 0 0 rgba(99,102,241,0.4); }
          70% { box-shadow: 0 0 0 14px rgba(99,102,241,0); }
          100% { box-shadow: 0 0 0 0 rgba(99,102,241,0); }
        }

        /* Spinner */
        .spinner {
          width: 18px; height: 18px;
          border: 2px solid rgba(255,255,255,0.2);
          border-top-color: #fff;
          border-radius: 50%;
          animation: spin 0.7s linear infinite;
          display: inline-block;
          vertical-align: middle;
          margin-right: 8px;
        }
        @keyframes spin { to { transform: rotate(360deg); } }

        /* Main grid */
        .main-grid {
          max-width: 1400px;
          margin: 0 auto;
          padding: 0 2rem 4rem;
          display: flex;
          flex-direction: column;
          gap: 1.5rem;
        }

        /* Metric cards */
        .metrics-row {
          display: grid;
          grid-template-columns: repeat(auto-fit, minmax(200px, 1fr));
          gap: 1rem;
        }

        .metric-card {
          position: relative;
          background: rgba(255,255,255,0.03);
          border: 1px solid rgba(255,255,255,0.07);
          border-radius: 16px;
          padding: 1.25rem 1.5rem;
          display: flex;
          align-items: center;
          gap: 1rem;
          overflow: hidden;
          transition: border-color 0.3s, transform 0.2s;
        }
        .metric-card:hover {
          border-color: rgba(var(--accent-rgb, 99,102,241), 0.3);
          transform: translateY(-2px);
        }
        .metric-glow {
          position: absolute;
          top: -20px; left: -20px;
          width: 80px; height: 80px;
          background: radial-gradient(circle, var(--accent, #6366f1) 0%, transparent 70%);
          opacity: 0.12;
          pointer-events: none;
        }
        .metric-icon {
          font-size: 1.5rem;
          color: var(--accent, #6366f1);
          flex-shrink: 0;
        }
        .metric-value {
          font-size: 1.5rem;
          font-weight: 800;
          color: #fff;
          letter-spacing: -0.03em;
          line-height: 1;
          margin-bottom: 2px;
        }
        .metric-label {
          font-size: 0.7rem;
          font-weight: 600;
          color: #6b7280;
          text-transform: uppercase;
          letter-spacing: 0.08em;
        }

        /* Section cards */
        .card {
          background: rgba(255,255,255,0.02);
          border: 1px solid rgba(255,255,255,0.07);
          border-radius: 20px;
          overflow: hidden;
        }
        .card-header {
          padding: 1.25rem 1.5rem;
          border-bottom: 1px solid rgba(255,255,255,0.06);
          display: flex;
          align-items: center;
          justify-content: space-between;
        }
        .card-title {
          font-size: 0.9375rem;
          font-weight: 700;
          color: #fff;
          letter-spacing: -0.01em;
        }

        /* Split row */
        .split-row {
          display: grid;
          grid-template-columns: 1fr 1fr;
          gap: 1.5rem;
        }
        @media (max-width: 768px) {
          .split-row { grid-template-columns: 1fr; }
          .metrics-row { grid-template-columns: 1fr 1fr; }
        }

        /* Score section */
        .scores-inner {
          padding: 2rem;
          display: flex;
          justify-content: space-around;
          align-items: center;
        }
        .score-divider {
          width: 1px;
          height: 80px;
          background: linear-gradient(to bottom, transparent, rgba(255,255,255,0.1), transparent);
        }

        /* Vuln table */
        .vuln-table { width: 100%; border-collapse: collapse; }
        .vuln-table th {
          padding: 0.75rem 1.5rem;
          font-size: 0.6875rem;
          font-weight: 700;
          color: #4b5563;
          text-transform: uppercase;
          letter-spacing: 0.1em;
          text-align: left;
          background: rgba(255,255,255,0.02);
          border-bottom: 1px solid rgba(255,255,255,0.06);
        }
        .vuln-row {
          border-bottom: 1px solid rgba(255,255,255,0.04);
          transition: background 0.2s;
          animation: rowIn 0.4s ease both;
        }
        .vuln-row:hover { background: rgba(255,255,255,0.03); }
        @keyframes rowIn {
          from { opacity: 0; transform: translateX(-8px); }
          to { opacity: 1; transform: translateX(0); }
        }

        /* Filter tabs */
        .filter-tabs {
          display: flex;
          gap: 6px;
          flex-wrap: wrap;
        }
        .filter-tab {
          padding: 4px 12px;
          border-radius: 9999px;
          font-size: 0.7rem;
          font-weight: 700;
          letter-spacing: 0.05em;
          cursor: pointer;
          border: 1px solid rgba(255,255,255,0.08);
          background: transparent;
          color: #6b7280;
          font-family: 'Syne', sans-serif;
          transition: all 0.2s;
        }
        .filter-tab.active {
          background: #6366f1;
          color: #fff;
          border-color: #6366f1;
        }
        .filter-tab:not(.active):hover {
          color: #fff;
          border-color: rgba(255,255,255,0.2);
        }

        /* PR cards */
        .pr-grid {
          display: grid;
          grid-template-columns: repeat(auto-fill, minmax(260px, 1fr));
          gap: 1rem;
          padding: 1.5rem;
        }
        .pr-card {
          background: rgba(255,255,255,0.02);
          border: 1px solid rgba(255,255,255,0.07);
          border-radius: 14px;
          padding: 1.25rem;
          transition: border-color 0.3s, transform 0.2s;
          animation: rowIn 0.4s ease both;
        }
        .pr-card:hover {
          border-color: rgba(99,102,241,0.3);
          transform: translateY(-2px);
        }

        /* Error banner */
        .error-banner {
          background: rgba(239,68,68,0.08);
          border: 1px solid rgba(239,68,68,0.2);
          border-radius: 12px;
          padding: 1rem 1.5rem;
          color: #fca5a5;
          font-size: 0.875rem;
          display: flex;
          align-items: center;
          gap: 0.75rem;
        }

        /* Empty state */
        .empty-state {
          text-align: center;
          padding: 4rem 2rem;
          color: #374151;
        }
        .empty-state .material-symbols-outlined {
          font-size: 3rem;
          margin-bottom: 1rem;
          display: block;
        }

        /* Count badge */
        .count-badge {
          background: rgba(239,68,68,0.12);
          color: #f87171;
          border: 1px solid rgba(239,68,68,0.2);
          border-radius: 9999px;
          padding: 2px 10px;
          font-size: 0.7rem;
          font-weight: 700;
        }

        .material-symbols-outlined {
          font-family: 'Material Symbols Outlined';
          font-weight: normal;
          font-style: normal;
          font-size: 20px;
          display: inline-block;
          line-height: 1;
          text-transform: none;
          letter-spacing: normal;
          word-wrap: normal;
          white-space: nowrap;
          direction: ltr;
        }

        .font-mono { font-family: 'JetBrains Mono', monospace; }
      `}</style>

      <div className="dashboard-root">
        <div className="content">
          {/* ── Nav ── */}
          <nav className="top-nav">
            <div
              style={{ display: "flex", alignItems: "center", gap: "2.5rem" }}
            >
              <span className="logo">⬡ CodeGuard</span>
              <div className="nav-links">
                <span className="nav-link active">Dashboard</span>
                <span className="nav-link">Reports</span>
                <span className="nav-link">Settings</span>
              </div>
            </div>
            <div style={{ display: "flex", alignItems: "center", gap: "1rem" }}>
              <div
                style={{
                  display: "flex",
                  alignItems: "center",
                  gap: "6px",
                  fontSize: "0.75rem",
                  color: "#6b7280",
                }}
              >
                <span className={`api-dot ${apiStatus}`} />
                API {apiStatus}
              </div>
              <div
                style={{
                  width: 32,
                  height: 32,
                  borderRadius: "50%",
                  background: "linear-gradient(135deg,#6366f1,#8b5cf6)",
                  display: "flex",
                  alignItems: "center",
                  justifyContent: "center",
                }}
              >
                <span
                  className="material-symbols-outlined"
                  style={{ fontSize: 16, color: "#fff" }}
                >
                  person
                </span>
              </div>
            </div>
          </nav>

          {/* ── Hero ── */}
          <section className="hero">
            <div className="hero-glow" />
            <h1>
              One-Click Security
              <br />
              Audit
            </h1>
            <p>
              Detect vulnerabilities across your codebase in seconds. Powered by
              AI — zero config needed.
            </p>

            <div className="mode-toggle">
              <button
                className={`mode-btn ${scanMode === "demo" ? "active" : "inactive"}`}
                onClick={() => setScanMode("demo")}
              >
                DEMO
              </button>
              <button
                className={`mode-btn ${scanMode === "live" ? "active" : "inactive"}`}
                onClick={() => setScanMode("live")}
              >
                LIVE API
              </button>
            </div>

            <br />

            <button
              className={`run-btn ${!loading && !auditData ? "pulse" : ""}`}
              onClick={handleRunAudit}
              disabled={loading}
            >
              {loading ? (
                <>
                  <span className="spinner" />
                  Scanning Codebase…
                </>
              ) : auditData ? (
                <>
                  <span
                    className="material-symbols-outlined"
                    style={{
                      verticalAlign: "middle",
                      marginRight: 8,
                      fontSize: 18,
                    }}
                  >
                    refresh
                  </span>
                  Re-run Audit
                </>
              ) : (
                <>
                  <span
                    className="material-symbols-outlined"
                    style={{
                      verticalAlign: "middle",
                      marginRight: 8,
                      fontSize: 18,
                    }}
                  >
                    play_arrow
                  </span>
                  Run Audit Now
                </>
              )}
            </button>

            {lastAudit && (
              <p
                style={{
                  marginTop: "1rem",
                  fontSize: "0.75rem",
                  color: "#4b5563",
                }}
              >
                <span
                  className="material-symbols-outlined"
                  style={{
                    fontSize: 14,
                    verticalAlign: "middle",
                    marginRight: 4,
                  }}
                >
                  history
                </span>
                Last scan at {lastAudit}
              </p>
            )}
          </section>

          <div className="main-grid">
            {/* ── Error ── */}
            {error && (
              <div className="error-banner">
                <span className="material-symbols-outlined">error</span>
                {error}
              </div>
            )}

            {/* ── Metrics ── */}
            {auditData && (
              <div className="metrics-row">
                <MetricCard
                  label="Score Before"
                  value={`${Math.max(10, beforeScore)}%`}
                  icon="trending_down"
                  accent="#ef4444"
                />
                <MetricCard
                  label="Score After"
                  value={`${afterScore ?? 92}%`}
                  icon="trending_up"
                  accent="#10b981"
                />
                <MetricCard
                  label="Time Saved"
                  value={`${auditData.impact.time_saved_hours}h`}
                  icon="schedule"
                  accent="#6366f1"
                />
                <MetricCard
                  label="Cost Saved"
                  value={auditData.impact.savings}
                  icon="payments"
                  accent="#8b5cf6"
                />
                {metrics && (
                  <MetricCard
                    label="Efficiency"
                    value={metrics.efficiency_improvement}
                    icon="bolt"
                    accent="#f59e0b"
                  />
                )}
              </div>
            )}

            {/* ── Scores + Summary ── */}
            {auditData && (
              <div className="split-row">
                <div className="card">
                  <div className="card-header">
                    <span className="card-title">Score Comparison</span>
                  </div>
                  <div className="scores-inner">
                    <ScoreRing
                      score={Math.max(10, beforeScore)}
                      label="Before"
                      color="#ef4444"
                    />
                    <div className="score-divider" />
                    <ScoreRing
                      score={afterScore ?? 92}
                      label="After"
                      color="#10b981"
                    />
                  </div>
                </div>

                <div className="card">
                  <div className="card-header">
                    <span className="card-title">Severity Breakdown</span>
                    <span className="count-badge">
                      {auditData.summary.total} total
                    </span>
                  </div>
                  <div style={{ padding: "1.5rem" }}>
                    <SummaryBar summary={auditData.summary} />
                    <div
                      style={{
                        marginTop: "1.5rem",
                        padding: "1rem",
                        borderRadius: 12,
                        background: "rgba(255,255,255,0.02)",
                        border: "1px solid rgba(255,255,255,0.05)",
                      }}
                    >
                      <p
                        style={{
                          fontSize: "0.7rem",
                          color: "#6b7280",
                          fontWeight: 600,
                          textTransform: "uppercase",
                          letterSpacing: "0.08em",
                          marginBottom: 4,
                        }}
                      >
                        Estimated Fix Time
                      </p>
                      <p
                        style={{
                          fontSize: "1.25rem",
                          fontWeight: 800,
                          color: "#fff",
                        }}
                      >
                        {auditData.impact.time_saved_minutes} minutes
                      </p>
                      <p
                        style={{
                          fontSize: "0.75rem",
                          color: "#4b5563",
                          marginTop: 2,
                        }}
                      >
                        vs {auditData.impact.manual_review_cost} manual review
                      </p>
                    </div>
                  </div>
                </div>
              </div>
            )}

            {/* ── Vulnerabilities Table ── */}
            {auditData && (
              <div className="card">
                <div className="card-header">
                  <div
                    style={{
                      display: "flex",
                      alignItems: "center",
                      gap: "0.75rem",
                    }}
                  >
                    <span className="card-title">Detected Vulnerabilities</span>
                    <span className="count-badge">
                      {auditData.summary.total} Issues
                    </span>
                  </div>
                  <div className="filter-tabs">
                    {["ALL", "CRITICAL", "HIGH", "MEDIUM", "LOW"].map((s) => (
                      <button
                        key={s}
                        className={`filter-tab ${severityFilter === s ? "active" : ""}`}
                        onClick={() => setSeverityFilter(s)}
                      >
                        {s}
                      </button>
                    ))}
                  </div>
                </div>
                {filteredVulns.length > 0 ? (
                  <div style={{ overflowX: "auto" }}>
                    <table className="vuln-table">
                      <thead>
                        <tr>
                          <th>File</th>
                          <th>Issue Type</th>
                          <th>Severity</th>
                          <th>Confidence</th>
                          <th>PR Fix</th>
                          <th></th>
                        </tr>
                      </thead>
                      <tbody>
                        {filteredVulns.map((v, i) => (
                          <VulnRow
                            key={`${v.file}-${v.line}-${i}`}
                            vuln={v}
                            index={i}
                          />
                        ))}
                      </tbody>
                    </table>
                  </div>
                ) : (
                  <div className="empty-state">
                    <span className="material-symbols-outlined">
                      search_off
                    </span>
                    <p>No vulnerabilities found for this filter.</p>
                  </div>
                )}
              </div>
            )}

            {/* ── PR Cards ── */}
            {auditData && auditData.vulnerabilities.length > 0 && (
              <div className="card">
                <div className="card-header">
                  <span className="card-title">Auto-Generated PRs</span>
                  <button
                    style={{
                      fontSize: "0.75rem",
                      color: "#6366f1",
                      fontWeight: 700,
                      background: "none",
                      border: "none",
                      cursor: "pointer",
                      fontFamily: "Syne, sans-serif",
                    }}
                  >
                    View all →
                  </button>
                </div>
                <div className="pr-grid">
                  {auditData.vulnerabilities.slice(0, 6).map((v, i) => (
                    <PRCard key={i} vuln={v} index={i} />
                  ))}
                </div>
              </div>
            )}

            {/* ── Empty state ── */}
            {!auditData && !loading && (
              <div
                className="card"
                style={{ padding: "5rem 2rem", textAlign: "center" }}
              >
                <span
                  className="material-symbols-outlined"
                  style={{
                    fontSize: "3.5rem",
                    color: "#1f2937",
                    marginBottom: "1rem",
                    display: "block",
                  }}
                >
                  security
                </span>
                <p
                  style={{
                    color: "#374151",
                    fontSize: "0.9rem",
                    maxWidth: 320,
                    margin: "0 auto",
                  }}
                >
                  Click{" "}
                  <strong style={{ color: "#6366f1" }}>Run Audit Now</strong>{" "}
                  above to scan your codebase for vulnerabilities.
                </p>
              </div>
            )}
          </div>
        </div>
      </div>
    </>
  );
}
